toast.usage:
const { toast } = useToast();

// A bare string
toast.show('Link copied');

// A config object
toast.show({
  variant: 'success',
  label: 'Deployment complete',
  description: 'panelui.dev is live on production.',
  actionLabel: 'View',
  onActionPress: ({ hide }) => hide(),
});

// A custom component
toast.show({
  component: ({ hide }) => (
    <Toast variant="info" onHide={hide}>
      <Toast.Indicator />
      <Toast.Content>
        <Toast.Title>Custom</Toast.Title>
      </Toast.Content>
      <Toast.Close />
    </Toast>
  ),
});
